query:
UPDATE site_content SET value = 'Essence of Duality' WHERE `key` = 'hero_title' AND lang = 'en';
UPDATE site_content SET value = 'Where Raga Meets Jazz' WHERE `key` = 'hero_subtitle' AND lang = 'en';
UPDATE site_content SET value = 'An exploration of the space between Indian classical music and jazz, where raga and improvisation meet in unexpected and beautiful ways.' WHERE `key` = 'hero_quote' AND lang = 'en';
UPDATE site_content SET value = 'Essence of Duality is the debut crossover jazz album by Cologne-based sitarist Hindol Deb, released on 1 October 2021 on Medieval Raga Records. The album explores and crosses the boundaries of jazz and Indian classical music, recorded in Cologne with four exceptional European jazz musicians, featuring nine original compositions rooted in specific ragas and reinterpreted through jazz harmonies.' WHERE `key` = 'album_description' AND lang = 'en';
UPDATE site_content SET value = '1 October 2021' WHERE `key` = 'album_release' AND lang = 'en';
UPDATE site_content SET value = 'It began with the duality of two musical styles. On one hand my classical Indian background that I brought with me to Germany, and on the other hand music built on harmonies. I wanted to find a way to bring these two worlds together — not as a compromise, but as a genuine conversation.' WHERE `key` = 'artist_quote' AND lang = 'en';
UPDATE site_content SET value = 'Each composition on the album is rooted in a specific raga — the melodic framework of Indian classical music that defines not just the notes, but the mood, time of day, and emotional essence of the music.' WHERE `key` = 'ragas_intro' AND lang = 'en';
UPDATE site_content SET value = 'Hindol Deb is an internationally renowned Indian classical sitarist whose artistry is defined by a profound adherence to his traditional heritage and a visionary quest for musical expansion. Representing the celebrated Maihar and Rampur Gharanas, Hindol has established himself as a virtuoso who bridges the ancient spiritual depth of the Raga with the infinite possibilities of global contemporary music.\n\nBorn in Kolkata and trained under the legendary Pandit Bimalendu Mukherjee, Hindol moved to Cologne, Germany, where he has been based for over two decades. He is the recipient of the DAAD scholarship and has been recognised by the German government for his contributions to cultural exchange.\n\nAs founder of the Medieval Raga Academy in Cologne, he is deeply committed to passing on the tradition to students worldwide.' WHERE `key` = 'artist_bio' AND lang = 'en';

INSERT INTO site_content (`key`, lang, value) VALUES
('hero_title', 'de', 'Essence of Duality'),
('hero_subtitle', 'de', 'Wo Raga auf Jazz trifft'),
('hero_quote', 'de', 'Eine Erkundung des Raums zwischen indischer klassischer Musik und Jazz, wo Raga und Improvisation auf unerwartete und wunderschöne Weise aufeinandertreffen.'),
('album_description', 'de', 'Essence of Duality ist das Debüt-Crossover-Jazz-Album des in Köln lebenden Sitaristen Hindol Deb, das am 1. Oktober 2021 über Medieval Raga Records veröffentlicht wurde. Das Album erkundet und überschreitet die Grenzen von Jazz und indischer klassischer Musik. In Köln mit vier außergewöhnlichen europäischen Jazzmusikern aufgenommen, enthält das Album neun Originalkompositionen, die in spezifischen Ragas verwurzelt und durch Jazzharmonien neu interpretiert sind.'),
('album_release', 'de', '1. Oktober 2021'),
('album_label', 'de', 'Medieval Raga Records'),
('artist_quote', 'de', 'Es begann mit der Dualität zweier Musikstile. Einerseits mein klassisch-indischer Hintergrund, den ich mit nach Deutschland brachte, und andererseits auf Harmonien aufgebaute Musik. Ich wollte einen Weg finden, diese beiden Welten zusammenzubringen — nicht als Kompromiss, sondern als echtes Gespräch.'),
('ragas_intro', 'de', 'Jede Komposition auf dem Album ist in einem bestimmten Raga verwurzelt — dem melodischen Rahmen der indischen klassischen Musik, der nicht nur die Noten, sondern auch die Stimmung, die Tageszeit und das emotionale Wesen der Musik definiert.'),
('artist_bio', 'de', 'Hindol Deb ist ein international renommierter indischer klassischer Sitarist, dessen Kunst durch eine tiefe Verbundenheit mit seinem traditionellen Erbe und eine visionäre Suche nach musikalischer Erweiterung geprägt ist. Als Vertreter der gefeierten Maihar- und Rampur-Gharanas hat sich Hindol als Virtuose etabliert, der die alte spirituelle Tiefe des Raga mit den unendlichen Möglichkeiten der globalen zeitgenössischen Musik verbindet.\n\nIn Kalkutta geboren und unter dem legendären Pandit Bimalendu Mukherjee ausgebildet, zog Hindol nach Köln, wo er seit über zwei Jahrzehnten lebt. Er ist DAAD-Stipendiat und wurde von der deutschen Regierung für seinen Beitrag zum Kulturaustausch ausgezeichnet.\n\nAls Gründer der Medieval Raga Academy in Köln ist er tief dem Weitergeben der Tradition verpflichtet.');

